RECURSION_WITH_BASE_CASE.code:
int factorial(int n) {
  if (n <= 1) return 1;  // base case
  return n * factorial(n - 1);
}

FIBONACCI_BASE_CASE.code:
int fibonacci(int n) {
  if (n == 0) return 0;
  if (n == 1) return 1;
  return fibonacci(n - 1) + fibonacci(n - 2);
}

