BUBBLE_SORT_CORRECT.code:
for (int i = 0; i < n - 1; i++) {
  for (int j = 0; j < n - 1 - i; j++) {
    if (a[j] > a[j + 1]) {
      swap(a[j], a[j + 1]);
    }
  }
}

BINARY_SEARCH_CORRECT.code:
int left = 0, right = n - 1;
while (left <= right) {
  int mid = (left + right) / 2;
  if (a[mid] == x) return mid;
  else if (a[mid] < x) left = mid + 1;
  else right = mid - 1;
}
return -1;  // không tìm thấy
